const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

// ============================================================
// Dispatcher: dedup against DB, fetch org context, chunk grants.
// Emits one item per ~300-grant chunk. Downstream Execute Workflow
// node runs the sub-workflow once per item, so every chunk gets its
// own 300s runner budget — unbounded total grant count.
// ============================================================

const CHUNK_SIZE = 300;
const DEDUP_BATCH = 200;

const items = $input.all();

let orgId, callbackUrl;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  orgId = webhookData?.org_id;
  callbackUrl = webhookData?.callback_url;
} catch(e) {}

if (!orgId) {
  return [{ json: { error: true, message: 'No org_id provided' } }];
}

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};
const supaReadHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
};
const webhookHeaders = {
  'Content-Type': 'application/json',
  'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
};

async function sendStatus(status, stage_message) {
  if (!callbackUrl || !orgId) return;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: callbackUrl,
      headers: webhookHeaders,
      body: { org_id: orgId, status, stage_message }
    });
  } catch(e) {}
}

await sendStatus.call(this, 'checking', 'Checking for duplicates in your pipeline...');

const allItems = items.map(i => i.json);
const oppNums = allItems
  .map(g => (g.oppNum || '').trim())
  .filter(id => id.length > 0);

const existingOppNums = new Set();
for (let i = 0; i < oppNums.length; i += DEDUP_BATCH) {
  const chunk = oppNums.slice(i, i + DEDUP_BATCH);
  const filter = chunk.map(id => '"' + id.replace(/"/g, '') + '"').join(',');
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/grants?source_id=in.(' + filter + ')&org_id=eq.' + orgId + '&select=source_id',
      headers: supaReadHeaders,
    });
    if (Array.isArray(response)) {
      for (const r of response) existingOppNums.add((r.source_id || '').trim());
    }
  } catch(e) {}
}

const newGrants = [];
for (const grant of allItems) {
  const oppNum = (grant.oppNum || '').trim();
  if (!oppNum || existingOppNums.has(oppNum)) continue;
  newGrants.push(grant);
}

if (newGrants.length === 0) {
  await sendStatus.call(this, 'complete', 'Grant search complete!');
  return [{ json: { noNewGrants: true, success: true, message: 'All grants already tracked', totalInserted: 0 } }];
}

// Log source counts
const sourceCounts = {};
for (const grant of newGrants) {
  const source = grant.source || 'Unknown';
  sourceCounts[source] = (sourceCounts[source] || 0) + 1;
}
const today = new Date().toISOString().split('T')[0];
try {
  await this.helpers.httpRequest({
    method: 'DELETE',
    url: supabaseUrl + '/grant_source_stats?org_id=eq.' + orgId + '&fetch_date=eq.' + today,
    headers: supaHeaders,
  });
  const rows = Object.entries(sourceCounts).map(([source, raw_count]) => ({
    org_id: orgId, source, raw_count, fetch_date: today
  }));
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/grant_source_stats',
    headers: supaHeaders,
    body: JSON.stringify(rows),
  });
} catch(e) {}

// Fetch org + narratives once
const orgs = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/organizations?id=eq.' + encodeURIComponent(orgId) + '&select=id,geographic_focus,address',
  headers: supaReadHeaders,
});
if (!Array.isArray(orgs) || orgs.length === 0) {
  return [{ json: { error: true, message: 'Organization not found: ' + orgId } }];
}
const org = orgs[0];

const narratives = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/documents?org_id=eq.' + encodeURIComponent(orgId) + '&select=title,extracted_text,category&order=updated_at.desc&limit=10',
  headers: supaReadHeaders,
});
let nicheSummary = '';
if (Array.isArray(narratives) && narratives.length > 0) {
  nicheSummary = narratives.map(n => (n.title || n.category || '') + ': ' + (n.extracted_text || '')).join('\n\n');
}

// Normalize grant shape for sub-workflow
const allGrantsForAI = newGrants.map(grant => ({
  title: grant.title || '',
  agency: grant.agency || null,
  agencyCode: grant.agencyCode || '',
  description: grant.description || '',
  awardFloor: grant.awardFloor || 0,
  awardCeiling: grant.awardCeiling || 0,
  openDate: grant.openDate || '',
  closeDate: grant.closeDate || '',
  status: grant.status || '',
  source: grant.source || 'Grant Scanner',
  source_id: grant.oppNum || grant.source_id,
  source_url: grant.link || grant.source_url,
  oppNum: grant.oppNum || grant.source_id,
  id: grant.id,
  link: grant.link || grant.source_url,
}));

// Split into chunks — one item per chunk → Execute Workflow runs once per item
const totalChunks = Math.ceil(allGrantsForAI.length / CHUNK_SIZE);
const output = [];
for (let i = 0; i < totalChunks; i++) {
  const chunk = allGrantsForAI.slice(i * CHUNK_SIZE, (i + 1) * CHUNK_SIZE);
  output.push({
    json: {
      org_id: orgId,
      org,
      nicheSummary,
      callbackUrl: callbackUrl || null,
      chunk_index: i,
      total_chunks: totalChunks,
      grants: chunk,
    }
  });
}

await sendStatus.call(this, 'filtering', 'Dispatching ' + allGrantsForAI.length + ' grants across ' + totalChunks + ' chunks...');

return output;

// Aggregate sub-workflow results and send final status
const items = $input.all();

let orgId, callbackUrl;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  orgId = webhookData?.org_id;
  callbackUrl = webhookData?.callback_url;
} catch(e) {}

let totalInserted = 0;
let totalScreened = 0;
let totalGrants = 0;
for (const it of items) {
  const j = it.json || {};
  totalInserted += j.inserted || 0;
  totalScreened += j.screened || 0;
  totalGrants += j.total || 0;
}

if (callbackUrl && orgId) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: callbackUrl,
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
      },
      body: { org_id: orgId, status: 'complete', stage_message: 'Grant search complete!' }
    });
  } catch(e) {}
}

return [{ json: { success: true, totalInserted, totalScreened, totalGrants, chunks: items.length } }];

// Status callback helper: only sends status if callback_url exists (new org registration)
// This node is placed at different stages of the pipeline
const items = $input.all();

// Try to get webhook data
let callbackUrl, orgId, webhookSecret;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  callbackUrl = webhookData?.callback_url;
  orgId = webhookData?.org_id;
  webhookSecret = webhookData?.is_new_org;
} catch(e) {
  // Not triggered via webhook (scheduled run) - skip status updates
  return items;
}

if (!callbackUrl || !orgId) return items;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
    },
    body: {
      org_id: orgId,
      status: 'searching',
      stage_message: 'Searching Grants.gov and federal databases...'
    }
  });
} catch(e) {
  // Don't fail the workflow if status update fails
}

return items;

// ============================================================
// Fetch Central Grants
// Pulls from the central_grants catalog instead of scraping
// external sources. The daily ingest workflow keeps the catalog
// fresh; this node just reads from it and hands rows downstream
// to Combine & Deduplicate → Dispatcher → Sub-workflow.
// ============================================================

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

const pageSize = 1000;
const selectCols = 'id,title,funder_name,organization,description,source,source_id,source_url,deadline,amount,eligibility,categories,metadata,last_seen_at';

let rows = [];
let offset = 0;
while (true) {
  const url = supabaseUrl + '/central_grants?select=' + selectCols + '&limit=' + pageSize + '&offset=' + offset + '&order=last_seen_at.desc';
  let page = [];
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey },
    });
    if (Array.isArray(res)) page = res;
  } catch (e) { break; }
  rows = rows.concat(page);
  if (page.length < pageSize) break;
  offset += pageSize;
}

// Drop expired grants. Null deadline = rolling/open-ended → keep.
const todayIso = new Date().toISOString().slice(0, 10);
const live = rows.filter(r => !r.deadline || r.deadline >= todayIso);

// Shape each row for downstream nodes. Dispatcher keys off `oppNum` for dedup.
return live.map(r => ({
  json: {
    id: r.id,
    oppNum: r.source_id || r.id,
    title: r.title || '',
    description: r.description || '',
    agency: r.funder_name || '',
    funder_name: r.funder_name || '',
    organization: r.organization || '',
    source: r.source || '',
    source_id: r.source_id || null,
    source_url: r.source_url || null,
    link: r.source_url || null,
    deadline: r.deadline || null,
    closeDate: r.deadline || null,
    amount: r.amount || null,
    eligibility: r.eligibility || null,
    categories: r.categories || null,
    metadata: r.metadata || null,
  },
}));
